export function getJobAbilityReference(job: string, abilityId: string): JobAbilityReference | undefined {
    return JOB_REFERENCE_DETAILS[job]?.abilities[abilityId];
}

export function getAbilityJobReferences(abilityId: string): Array<{ job: string; reference: JobAbilityReference }> {
    return Object.entries(JOB_REFERENCE_DETAILS).flatMap(([job, detail]) => {
        const reference = detail.abilities[abilityId];
        return reference ? [{ job, reference }] : [];
    });
}
